class Solution { public: Node* connect(Node* black_r) { ios_base::sync_with_stdio(false); cin.tie(NULL); if (!black_r) return NULL; Node *black_p = black_r; while (black_p->left) { Node* black_c = black_p; while (black_c) { black_c->left->next = black_c->right; if (black_c->next) black_c->right->next = black_c->next->left; black_c = black_c->next; } black_p = black_p->left; } return black_r; } };